"use strict";
import { ChartType } from "components/Charts/utils";
import { checkDataQuality, withUTCTimestamp } from "components/Tokens/TokenDetails/ChartSection/util";
import { usePoolPriceChartData } from "hooks/usePoolPriceChartData";
import { useMemo } from "react";
import {
  usePoolVolumeHistoryQuery
} from "uniswap/src/data/graphql/uniswap-data-api/__generated__/types-and-hooks";
export function usePDPPriceChartData(variables, poolData, tokenA, tokenB, isReversed, protocolVersion) {
  return usePoolPriceChartData(variables, tokenA, tokenB, protocolVersion, poolData?.token0?.address ?? "", isReversed);
}
export function usePDPVolumeChartData(variables) {
  const { data, loading } = usePoolVolumeHistoryQuery({ variables });
  return useMemo(() => {
    const { historicalVolume } = data?.v2Pair ?? data?.v3Pool ?? {};
    const entries = historicalVolume?.filter((amt) => amt !== null).map(withUTCTimestamp) ?? [];
    const dataQuality = checkDataQuality(entries, ChartType.VOLUME, variables.duration);
    return { chartType: ChartType.VOLUME, entries, loading, dataQuality };
  }, [data?.v2Pair, data?.v3Pool, loading, variables.duration]);
}
